insert into public.pages (key, title, hero, blocks, sort_order) values
(
  'home',
  $json${"en":"Amit Kochavi","he":"עמית כוכבי"}$json$,
  $json${"title":{"en":"Amit Kochavi","he":"עמית כוכבי"},"subtitle":{"en":"Building enterprises, continuing a family legacy of giving, and serving the people of Sderot.","he":"בונה מפעלים, ממשיך מורשת משפחתית של נתינה, ומשרת את תושבי שדרות."},"cta_label":{"en":"Learn more","he":"מידע נוסף"},"cta_href":"/about"}$json$,
  $json$[{"id":"home-intro","type":"text","heading":{"en":"A life across three commitments","he":"חיים של שלוש מחויבויות"},"body":{"en":"Amit Kochavi’s work spans the worlds of business, philanthropy, and public service. Each reinforces the others — enterprise that creates opportunity, giving that strengthens community, and service that puts people first.","he":"פועלו של עמית כוכבי משתרע על פני עולמות העסקים, הפילנתרופיה והשירות הציבורי. כל אחד מהם מחזק את האחרים — יזמות שיוצרת הזדמנות, נתינה שמחזקת קהילה, ושירות ששם את האדם במרכז."}},{"id":"home-pillars","type":"cards","heading":{"en":"Explore","he":"גלו עוד"},"items":[{"title":{"en":"Business","he":"עסקים"},"body":{"en":"A career building and backing companies that create lasting value and jobs.","he":"קריירה של בנייה וגיבוי חברות שיוצרות ערך ותעסוקה לאורך זמן."},"href":"/business"},{"title":{"en":"Philanthropy","he":"פילנתרופיה"},"body":{"en":"A fourth-generation tradition of giving, invested in people and community.","he":"מסורת נתינה מהדור הרביעי, המושקעת באנשים ובקהילה."},"href":"/philanthropy"},{"title":{"en":"Public Service","he":"שירות ציבורי"},"body":{"en":"Standing with Sderot and the Negev — resilience, recovery, and growth.","he":"עומד לצד שדרות והנגב — חוסן, שיקום וצמיחה."},"href":"/public-service"}]}]$json$,
  0
),
(
  'about',
  $json${"en":"About","he":"אודות"}$json$,
  $json${"title":{"en":"About Amit Kochavi","he":"אודות עמית כוכבי"},"subtitle":{"en":"Entrepreneur, investor, and public servant — building between Tel Aviv and Los Angeles.","he":"יזם, משקיע ואיש ציבור — בונה בין תל אביב ללוס אנג'לס."}}$json$,
  $json$[{"id":"about-bio","type":"text","body":{"en":"<p>I was born in Tel Aviv on December 10th, 1997, into a family that taught me two things early: that wealth is a responsibility before it is a privilege, and that nothing you inherit matters as much as what you build.</p><p>I'm a fourth-generation entrepreneur. On one side of my family stands Max Factor Sr., who left Łódź for Los Angeles and built one of the most recognized names in the history of beauty — proof that an immigrant with a craft and conviction can shape global culture. On the other side, generations of builders and investors in Israel and the United States who developed real estate, backed businesses, and gave back to the communities that made their success possible. Growing up between Tel Aviv and Los Angeles, I absorbed both worlds: Israeli directness and ambition, and American scale and institution-building.</p><p>In March 2019, at 21, I founded my first company, Circles Ltd. We started with an innovation-management platform, sold it to our first customers, and failed. So we did what founders do — we listened, pivoted, and rebuilt the company as Cormi, a workflow and forms platform serving businesses in construction and manufacturing, backed by leading Israeli investors including the owner of Tidhar, one of Israel's largest construction groups. The lesson of those years stays with me: resilience is not a slogan. It is the daily practice of showing up after the plan breaks.</p><p>Today I lead Starwell Holdings, the platform through which I build, invest, and advise — from technology services consolidation to large-scale urban development in Tel Aviv-Jaffa.</p><p>But the chapter that changed my life began on October 7th, 2023. In the aftermath of that day, I joined the Mayor of Sderot as a senior advisor, working alongside the Tkuma Directorate in the Prime Minister's Office to help structure the city's economic recovery and long-term development plan. Sderot taught me what business never could: that the hardest, most meaningful work is rebuilding a community's belief in its own future.</p><p>That work sits at the center of everything I do now — alongside board service at the Buchman Heyman Foundation and the Sharon &amp; Herb Glaser Foundation, membership in TAU Aurion, Tel Aviv University's next-generation leadership community, and participation in Voice of the People, the President of Israel's global council on the future of the Jewish people.</p><p>I split my time between Tel Aviv and Los Angeles. I believe in free markets, strong security, a pluralistic Israel, and an unbreakable bond between Israel and the Jewish Diaspora. And I believe the next generation of Israeli leadership has to be built the old way: by doing the work first.</p>","he":"<p>נולדתי בתל אביב ב-10 בדצמבר 1997, למשפחה שלימדה אותי שני דברים כבר בגיל צעיר: שעושר הוא אחריות לפני שהוא זכות, ושדבר מכל מה שאתה יורש אינו חשוב כמו מה שאתה בונה בעצמך.</p><p>אני יזם מהדור הרביעי. בצד אחד של משפחתי עומד מקס פקטור האב, שעזב את לודז' לטובת לוס אנג'לס ובנה אחד מהשמות המוכרים ביותר בתולדות עולם היופי — הוכחה לכך שמהגר בעל מלאכה והכרה יכול לעצב תרבות גלובלית. בצד השני, דורות של בונים ומשקיעים בישראל ובארצות הברית, שפיתחו נדל\"ן, גיבו עסקים, והחזירו לקהילות שאפשרו את הצלחתם. כשגדלתי בין תל אביב ללוס אנג'לס, ספגתי את שני העולמות: הישירות והשאפתנות הישראלית, והעוצמה ובניית המוסדות האמריקאית.</p><p>במרץ 2019, בגיל 21, הקמתי את החברה הראשונה שלי, Circles Ltd. התחלנו עם פלטפורמה לניהול חדשנות, מכרנו ללקוחותינו הראשונים — ונכשלנו. אז עשינו את מה שיזמים עושים: הקשבנו, ביצענו פיבוט, ובנינו מחדש את החברה כ-Cormi, פלטפורמת תהליכים וטפסים המשרתת עסקים בתחומי הבנייה והייצור, בגיבוי משקיעים ישראליים מובילים ובהם הבעלים של תדהר, אחת מקבוצות הבנייה הגדולות בישראל. הלקח של אותן שנים נותר עמי: חוסן אינו סיסמה. הוא התרגול היומיומי של לקום שוב לאחר שהתוכנית מתנפצת.</p><p>כיום אני עומד בראש Starwell Holdings, הפלטפורמה שדרכה אני בונה, משקיע ומייעץ — מאיחוד שירותי טכנולוגיה ועד התחדשות עירונית בקנה מידה גדול בתל אביב-יפו.</p><p>אך הפרק ששינה את חיי החל ב-7 באוקטובר 2023. בעקבות אותו יום הצטרפתי לראש עיריית שדרות כיועץ בכיר, ופעלתי לצד מינהלת תקומה במשרד ראש הממשלה כדי לעצב את תוכנית ההתאוששות הכלכלית והפיתוח ארוך-הטווח של העיר. שדרות לימדה אותי את מה שהעסקים מעולם לא יכלו: שהעבודה הקשה והמשמעותית ביותר היא לשקם את אמונתה של קהילה בעתידה.</p><p>עבודה זו ניצבת במרכז כל מה שאני עושה כיום — לצד חברות בדירקטוריונים של קרן בוכמן-היימן וקרן שרון והרב גלייזר, חברות ב-TAU Aurion, קהילת המנהיגות הצעירה של אוניברסיטת תל אביב, והשתתפות ב-Voice of the People, מועצת נשיא המדינה העולמית לעתיד העם היהודי.</p><p>אני מחלק את זמני בין תל אביב ללוס אנג'לס. אני מאמין בשווקים חופשיים, בביטחון חזק, בישראל פלורליסטית, ובברית בל-תינתק בין ישראל ליהדות התפוצות. ואני מאמין שעל הדור הבא של המנהיגות הישראלית להיבנות בדרך הישנה: קודם כול עושים את העבודה.</p>"}},{"id":"about-values","type":"quote","body":{"en":"Wealth is a responsibility before it is a privilege — and nothing you inherit matters as much as what you build.","he":"עושר הוא אחריות לפני שהוא זכות — ודבר ממה שאתה יורש אינו חשוב כמו מה שאתה בונה בעצמך."},"attribution":{"en":"Amit Kochavi","he":"עמית כוכבי"}}]$json$,
  1
),
(
  'business',
  $json${"en":"Business","he":"עסקים"}$json$,
  $json${"title":{"en":"Business Career","he":"קריירה עסקית"},"subtitle":{"en":"Building and backing companies that create lasting value.","he":"בנייה וגיבוי חברות שיוצרות ערך לאורך זמן."}}$json$,
  $json$[{"id":"biz-overview","type":"text","heading":{"en":"An entrepreneur’s path","he":"דרכו של יזם"},"body":{"en":"Across more than two decades, Amit Kochavi has founded, led, and invested in businesses spanning technology, real estate, and growth-stage enterprise. His approach pairs long-term vision with operational discipline — building companies designed to endure and to create meaningful employment.","he":"במשך למעלה משני עשורים ייסד עמית כוכבי, הוביל והשקיע בעסקים בתחומי הטכנולוגיה, הנדל\"ן וחברות בצמיחה. גישתו משלבת חזון ארוך-טווח עם משמעת תפעולית — בניית חברות שנועדו להתמיד וליצור תעסוקה משמעותית."}},{"id":"biz-stats","type":"stat","items":[{"value":{"en":"20+","he":"20+"},"label":{"en":"Years in business","he":"שנות פעילות עסקית"}},{"value":{"en":"Multiple","he":"מספר"},"label":{"en":"Companies founded & backed","he":"חברות שהוקמו וגובו"}},{"value":{"en":"Long-term","he":"ארוך-טווח"},"label":{"en":"Investment horizon","he":"אופק השקעה"}}]},{"id":"biz-approach","type":"text","heading":{"en":"Philosophy","he":"פילוסופיה"},"body":{"en":"Credibility, patience, and partnership define how Amit works. He invests in people first, builds trust over years, and measures returns not only in capital but in the opportunity and stability his ventures create.","he":"אמינות, סבלנות ושותפות מאפיינות את דרכו של עמית. הוא משקיע קודם כל באנשים, בונה אמון לאורך שנים, ומודד תשואה לא רק בהון אלא גם בהזדמנות וביציבות שמיזמיו יוצרים."}}]$json$,
  2
),
(
  'philanthropy',
  $json${"en":"Philanthropy","he":"פילנתרופיה"}$json$,
  $json${"title":{"en":"Philanthropy","he":"פילנתרופיה"},"subtitle":{"en":"A fourth-generation tradition of giving.","he":"מסורת נתינה מהדור הרביעי."}}$json$,
  $json$[{"id":"phil-legacy","type":"text","heading":{"en":"Four generations of giving","he":"ארבעה דורות של נתינה"},"body":{"en":"Philanthropy is, for Amit Kochavi, an inheritance and a responsibility. As a fourth-generation philanthropist, he carries forward a family legacy in which giving is not an occasional act but a way of life — directed toward education, community resilience, and opportunity for the next generation.","he":"עבור עמית כוכבי, הפילנתרופיה היא ירושה ואחריות כאחד. כפילנתרופ מהדור הרביעי, הוא ממשיך מורשת משפחתית שבה הנתינה אינה מעשה מזדמן אלא דרך חיים — המכוונת לחינוך, לחוסן קהילתי ולהזדמנות עבור הדור הבא."}},{"id":"phil-foundations","type":"cards","heading":{"en":"Our family foundations","he":"קרנות המשפחה שלנו"},"items":[{"title":{"en":"The Buchman Heyman Foundation","he":"קרן בוכמן־היימן"},"body":{"en":"Founded in 1942 by Sara Buchman.","he":"נוסדה ב-1942 על ידי שרה בוכמן."}},{"title":{"en":"The Herb & Sharon Glaser Foundation","he":"קרן הרב ושרון גלייזר"},"body":{"en":"","he":""}},{"title":{"en":"The Max Factor Family Foundation","he":"קרן משפחת מקס פקטור"},"body":{"en":"Continuing the legacy of Max Factor Sr.","he":"ממשיכה את מורשתו של מקס פקטור האב."}}]}]$json$,
