(
  'public-service',
  $json${"en":"Public Service","he":"שירות ציבורי"}$json$,
  $json${"title":{"en":"Public Service in Sderot","he":"שירות ציבורי בשדרות"},"subtitle":{"en":"Standing with the people of Sderot and the Negev.","he":"עומד לצד תושבי שדרות והנגב."}}$json$,
  $json$[{"id":"ps-sderot","type":"text","heading":{"en":"A commitment to Sderot","he":"מחויבות לשדרות"},"body":{"en":"Public service, for Amit Kochavi, begins close to home. He has dedicated himself to the people of Sderot — a community known for its extraordinary resilience — working to advance recovery, security, education, and long-term growth so that residents can build their futures with confidence.","he":"השירות הציבורי, עבור עמית כוכבי, מתחיל קרוב לבית. הוא הקדיש את עצמו לתושבי שדרות — קהילה הידועה בחוסנה יוצא הדופן — ופועל לקידום שיקום, ביטחון, חינוך וצמיחה ארוכת-טווח, כדי שהתושבים יוכלו לבנות את עתידם מתוך ביטחון."}},{"id":"ps-initiatives","type":"cards","heading":{"en":"Initiatives since October 7th","he":"יוזמות מאז ה-7 באוקטובר"},"items":[{"title":{"en":"Rimon Music School","he":"בית הספר למוזיקה רימון"},"body":{"en":"Founded a music school in Sderot. Budget ≈ ₪30M.","he":"הקמת בית ספר למוזיקה בשדרות. תקציב של כ-30 מיליון ש\"ח."}},{"title":{"en":"Seven Bilingual Kindergartens","he":"שבעה גני ילדים דו-לשוניים"},"body":{"en":"English–Hebrew kindergartens, with a multi-million-shekel budget.","he":"גנים דו-לשוניים באנגלית ובעברית, בתקציב של מיליוני שקלים."}},{"title":{"en":"Faculty of Technology, Sapir Academic College","he":"הפקולטה לטכנולוגיה במכללת ספיר"},"body":{"en":"Founding-team member of a new technology faculty in Sderot — 15,000 m² (≈161,500 sq ft) beside the train station. Budget ≈ ₪500M.","he":"חבר צוות מייסד של פקולטה חדשה לטכנולוגיה בשדרות — 15,000 מ\"ר (כ-161,500 רגל רבוע) סמוך לתחנת הרכבת. תקציב של כ-500 מיליון ש\"ח."}},{"title":{"en":"Tech Relocation to the Gaza Envelope","he":"רילוקיישן של הייטק לעוטף עזה"},"body":{"en":"A program bringing tech employees from central Israel to Sderot and the Gaza-envelope region — a ₪100M effort to attract over 400 families.","he":"תוכנית להבאת עובדי הייטק ממרכז הארץ לשדרות ולעוטף עזה — מאמץ בתקציב של 100 מיליון ש\"ח למשיכת למעלה מ-400 משפחות."}}]}]$json$,
